	bool flg = false;

	int n, p, cur;

	int curP;

	vector<int> s; 



	while (cin >> n >> p) {

		if (n == 0 && p == 0) {

			break;

		}

		// 初期化処理

		cur = 0;

		curP = p;

		s.clear();

		s.resize(n);



		// 現在の候補者が碗から石を取り出す

		// 番号が降ってあるわけではない！

		while (true) {

			// 現在ターンである候補者が1つ取り出す

			if (curP > 0) {

				s[cur]++;

				curP--;

			} else if (curP == 0 && s[cur] > 0) {// 手元に小石があれば全て碗の中に入れる

				curP += s[cur];

				s[cur] = 0;

			}



			// 条件を満たして入れば終了

