using namespace std;





set< string >res;

map< string, vector< string > >mmset;

map< string, bool >visited;



int N;

char buf[20];

int main(){

    string fst = "";

    while(true){

        cin>>N; if(N==0)break;

        res.clear();

        mmset.clear();

        visited.clear();

        for(int i=0;i<N;i++){

            int p = 0; char buf1; while((buf1 = getchar())&&buf1!=':'){

                buf[p++] = buf1;

            }

            string t = string(buf,p);

//             cout << "header: " << t << "!" << endl;

            if(i==0) fst = t;

            char inc; p = 0; while((inc = getchar()) && inc!='\n' && inc!='\r'){

                if(inc == ',' || inc == '.'){

                    string tt = string(buf, p);

                    mmset[t].push_back(tt);

//                     cout<<"found: "<<tt<<endl;

                    p = 0;

                } else {

                    buf[p++] = inc;

                }

            }

        }

        queue< string >workingset;

        workingset.push(fst);

        while(!workingset.empty()){

            string pivot = workingset.front(); workingset.pop();

            if(visited[pivot])continue;

            if(mmset.find(pivot)==mmset.end()){

                res.insert(pivot);

                visited[pivot] = true;

            } else {

                for(auto i = mmset[pivot].begin(); i!=mmset[pivot].end(); i++){

                    workingset.push(*i);

                }

                visited[pivot] = true;

            }

        }

        printf("%d\n",res.size());

    }

    return 0;

}

