pair<string, vector<string> > parse(string s)

{

    for(int i=0; i<s.size(); i++)

        if(!isalpha(s[i])) s[i] = ' ';



    s.erase(s.end() - 1);



    stringstream ss(s);

    string n;

    ss >> n;



    string a;

    vector<string> res;

    while(ss >> a) { res.push_back(a); }



    return make_pair(n, res); 

}



